// Let's just try to decompile the interesting types
using System.Reflection;

var asm = Assembly.LoadFrom(System.IO.Path.Combine(
    Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
    ".nuget/packages/microsoft.agents.ai/1.5.0/lib/net10.0/Microsoft.Agents.AI.dll"));

var types = new[] { "AgentResponse", "AgentRunOptions", "ChatClientAgentRunOptions", "ChatClientAgentOptions", "AgentResponseUpdate" };
foreach (var typeName in types)
{
    var type = asm.GetTypes().FirstOrDefault(t => t.Name == typeName);
    if (type == null) continue;
    Console.WriteLine($"\n=== {type.FullName} ===");
    foreach (var p in type.GetProperties(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  {p.PropertyType.Name} {p.Name}");
    foreach (var m in type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
        Console.WriteLine($"  method: {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p2 => $"{p2.ParameterType.Name} {p2.Name}"))})");
    foreach (var c in type.GetConstructors())
        Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p2 => $"{p2.ParameterType.Name} {p2.Name}"))})");
}
EOF
