using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// ── Tools ───────────────────────────────────────────────────────────────────
var notepad = new Notepad();
var webSearch = new WebSearcher();

var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearch.SearchWeb),
    AIFunctionFactory.Create(notepad.SaveNote),
    AIFunctionFactory.Create(notepad.GetNotes),
};

// ── Chat client (MEAI abstraction over OpenAI) ──────────────────────────────
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// ── Agent (Microsoft Agent Framework) ───────────────────────────────────────
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When given a topic:
        1. Use the SearchWeb tool multiple times with different queries to gather information.
        2. Use the SaveNote tool to record key findings as you go.
        3. After you have gathered enough information, use GetNotes to review your notes.
        4. Produce a well-structured summary with sections and source attributions.
        Keep searches focused and notes concise. Aim for breadth across the topic.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking.",
    tools: tools);

// ── Run ─────────────────────────────────────────────────────────────────────
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var session = await agent.CreateSessionAsync(cancellationToken: CancellationToken.None);

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions);

Console.WriteLine("═══════════════════════════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════════════════════════\n");

foreach (var message in response.Messages)
{
    if (message.Role == ChatRole.Assistant && message.Text is { Length: > 0 })
    {
        Console.WriteLine(message.Text);
    }
}

Console.WriteLine("\n═══════════════════════════════════════════════════════════════");
Console.WriteLine($"  Notes taken: {notepad.Count}");
Console.WriteLine("═══════════════════════════════════════════════════════════════");

// ── Tool implementations ────────────────────────────────────────────────────

/// <summary>Simple in-memory notepad for the agent to store findings.</summary>
sealed class Notepad
{
    private readonly List<(string Title, string Content)> _notes = [];

    public int Count => _notes.Count;

    [Description("Save a research note with a title and content. Use this to record key findings.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("Content of the note")] string content)
    {
        _notes.Add((title, content));
        return $"Note saved: \"{title}\" (note #{_notes.Count})";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"--- Note #{i + 1}: {n.Title} ---\n{n.Content}"));
    }
}

/// <summary>Web search tool that fetches real results via the Brave Search API or
/// falls back to a built-in simulation when no API key is configured.</summary>
sealed class WebSearcher
{
    private static readonly HttpClient Http = new();
    private readonly string? _braveApiKey = Environment.GetEnvironmentVariable("BRAVE_API_KEY");

    [Description("Search the web for information on a query. Returns a summary of the top results.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🌐 Searching: {query}");

        if (!string.IsNullOrEmpty(_braveApiKey))
            return await SearchBraveAsync(query);

        return GetSimulatedResults(query);
    }

    private async Task<string> SearchBraveAsync(string query)
    {
        using var request = new HttpRequestMessage(HttpMethod.Get,
            $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count=5");
        request.Headers.Add("X-Subscription-Token", _braveApiKey);
        request.Headers.Add("Accept", "application/json");

        using var response = await Http.SendAsync(request);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync();
        var doc = System.Text.Json.JsonDocument.Parse(json);

        var results = new List<string>();
        if (doc.RootElement.TryGetProperty("web", out var web) &&
            web.TryGetProperty("results", out var arr))
        {
            foreach (var item in arr.EnumerateArray().Take(5))
            {
                var title = item.GetProperty("title").GetString();
                var desc = item.TryGetProperty("description", out var d) ? d.GetString() : "";
                var url = item.GetProperty("url").GetString();
                results.Add($"- {title}\n  {desc}\n  Source: {url}");
            }
        }

        return results.Count > 0
            ? $"Search results for \"{query}\":\n\n{string.Join("\n\n", results)}"
            : $"No results found for \"{query}\".";
    }

    private static string GetSimulatedResults(string query)
    {
        var q = query.ToLowerInvariant();
        return $"""
            Search results for "{query}" (simulated — set BRAVE_API_KEY for live results):

            1. "Overview of {query} - Wikipedia"
               A comprehensive overview covering the history, key concepts, and current state of {query}.
               Major developments include recent advances and growing adoption across multiple domains.
               Source: https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query)}

            2. "Recent Advances in {query} - Nature"
               A 2024 review article examining the latest research breakthroughs related to {query}.
               Researchers have identified several promising directions for future work.
               Source: https://nature.com/articles/{Uri.EscapeDataString(query)}-review

            3. "{query}: Practical Applications and Industry Trends"
               Industry analysis showing that {query} is being adopted at an accelerating pace.
               Key sectors include technology, healthcare, education, and finance.
               Source: https://techreview.com/{Uri.EscapeDataString(query)}-trends

            4. "The Future of {query} - Expert Perspectives"
               Leading experts weigh in on where {query} is heading over the next decade.
               Consensus points to transformative potential with important ethical considerations.
               Source: https://futurism.com/{Uri.EscapeDataString(query)}-future

            5. "Getting Started with {query} - A Beginner's Guide"
               A practical guide for newcomers covering foundational concepts and resources.
               Includes recommended tools, communities, and learning paths.
               Source: https://learn.microsoft.com/{Uri.EscapeDataString(query)}-guide
            """;
    }
}

